                    -- 初始化自动备份设置
                    -- 使用延迟初始化，确保WebDKP_Options已加载
                    WebDKP_ScheduleTimer(function()
                      if not WebDKP_Options then
                        WebDKP_Options = {}
                      end
                      if WebDKP_Options["AutoBackupEnabled"] == nil then
                        WebDKP_Options["AutoBackupEnabled"] = false
                      end
                      getglobal("WebDKP_FiltersFrameCreatePlayerFrameAutoBackupCheck"):SetChecked(WebDKP_Options["AutoBackupEnabled"]);
                    end, 0.5);


                    -- 保存自动备份设置
                    if not WebDKP_Options then
                      WebDKP_Options = {}
                    end
                    WebDKP_Options["AutoBackupEnabled"] = this:GetChecked();
                    -- 确保设置被保存到磁盘
                    if WebDKP_SaveToDisk then
                      WebDKP_SaveToDisk();
                    end






























